+				parsing = false;
+				arg_idx--;
+				continue;
+
+			case '#':
+			case '-':
+			case '+':
+			case ' ':
+			case '0':
+			case '1':
+			case '2':
+			case '3':
+			case '4':
+			case '5':
+			case '6':
+			case '7':
+			case '8':
+			case '9':
+			case '.':
+			case 'h':
+			case 'l':
+			case 'L':
+				continue;
+
+			case '*':
+				break;
+
+			case 'j':
+				align = VA_STACK_ALIGN(intmax_t);
+				size = sizeof(intmax_t);
+				continue;
+
+			case 'z':
+				align = VA_STACK_ALIGN(size_t);
+				size = sizeof(size_t);
+				continue;
+
+			case 't':
+				align = VA_STACK_ALIGN(ptrdiff_t);
+				size = sizeof(ptrdiff_t);
+				continue;
+
+			case 'c':
+			case 'd':
+			case 'i':
+			case 'o':
+			case 'u':
+			case 'x':
+			case 'X':
