+					if (fmt[-2] == 'l') {
+						align = VA_STACK_ALIGN(long long);
+						size = sizeof(long long);
+					} else {
+						align = VA_STACK_ALIGN(long);
+						size = sizeof(long);
+					}
+				}
+				parsing = false;
+				break;
+
+			case 's':
+				is_str_arg = true;
+
+				__fallthrough;
+			case 'p':
+			case 'n':
+				align = VA_STACK_ALIGN(void *);
+				size = sizeof(void *);
+				parsing = false;
+				break;
+
+			case 'a':
+			case 'A':
+			case 'e':
+			case 'E':
+			case 'f':
+			case 'F':
+			case 'g':
+			case 'G': {
+				/*
+				 * Handle floats separately as they may be
+				 * held in a different register set.
+				 */
+				union { double d; long double ld; } v;
+
+				if (fmt[-1] == 'L') {
+					v.ld = va_arg(ap, long double);
+					align = VA_STACK_ALIGN(long double);
+					size = sizeof(long double);
+				} else {
+					v.d = va_arg(ap, double);
+					align = VA_STACK_ALIGN(double);
+					size = sizeof(double);
+				}
+				/* align destination buffer location */
+				buf = ROUND_UP(buf, align);
+				if (buf0 != NULL) {
+					/* make sure it fits */
+					if (BUF_OFFSET + size > len) {
+						return -ENOSPC;
+					}
