+					} else if (fmt[-1] == 'L') {
+						*(long double *)buf = v.ld;
+					} else {
+						*(double *)buf = v.d;
+					}
+				}
+				buf += size;
+				parsing = false;
+				continue;
+			}
+
+			default:
+				parsing = false;
+				continue;
+			}
+		}
