+				if (s_idx >= ARRAY_SIZE(str_ptr_pos)) {
+					__ASSERT(false, "str_ptr_pos[] too small");
+					return -EINVAL;
+				}
+
+				if (buf0 != NULL) {
+					/*
+					 * Remember string pointer location.
+					 * We will append non-ro strings later.
+					 */
+					str_ptr_pos[s_idx] = s_ptr_idx;
+					str_ptr_arg[s_idx] = arg_idx;
+					if (is_ro) {
+						/* flag read-only string. */
+						str_ptr_pos[s_idx] |= STR_POS_RO_FLAG;
+						s_ro_cnt++;
+					} else {
+						s_rw_cnt++;
+					}
+				} else if (is_ro) {
+					/*
+					 * Add only pointer position prefix
+					 * when counting strings.
+					 */
+					len += 1;
+				} else if (rws_pos_en) {
+					/*
+					 * Add only pointer position prefix and
+					 * argument index when counting strings.
+					 */
+					len += 2;
+				} else {
+					/*
+					 * Add the string length, the final '\0'
+					 * and size of the pointer position prefix.
+					 */
+					len += strlen(s) + 1 + 1;
+				}
+
+				s_idx++;
+			}
+			buf += sizeof(char *);
+
+			is_str_arg = false;
+		} else if (size == sizeof(int)) {
+			int v = va_arg(ap, int);
+
+			if (buf0 != NULL) {
+				*(int *)buf = v;
+			}
+			buf += sizeof(int);
+		} else if (size == sizeof(long)) {
+			long v = va_arg(ap, long);
+
+			if (buf0 != NULL) {
+				*(long *)buf = v;
+			}
+			buf += sizeof(long);
+		} else if (size == sizeof(long long)) {
+			long long v = va_arg(ap, long long);
+
+			if (buf0 != NULL) {
+				if (Z_CBPRINTF_VA_STACK_LL_DBL_MEMCPY) {
+					memcpy((void *)buf, (uint8_t *)&v, sizeof(long long));
+				} else {
+					*(long long *)buf = v;
+				}
+			}
+			buf += sizeof(long long);
+		} else {
+			__ASSERT(false, "unexpected size %u", size);
+			return -EINVAL;
+		}
+	}
+
+	/*
+	 * We remember the size of the argument list as a multiple of
+	 * sizeof(int) and limit it to a 8-bit field. That means 1020 bytes
+	 * worth of va_list, or about 127 arguments on a 64-bit system
+	 * (twice that on 32-bit systems). That ought to be good enough.
+	 */
+	if ((BUF_OFFSET / sizeof(int)) > 255) {
+		__ASSERT(false, "too many format args");
+		return -EINVAL;
+	}
+
+	/*
+	 * If all we wanted was to count required buffer size
+	 * then we have it now.
+	 */
+	if (buf0 == NULL) {
+		return BUF_OFFSET + len - CBPRINTF_PACKAGE_ALIGNMENT;
+	}
+
+	/* Clear our buffer header. We made room for it initially. */
+	*(char **)buf0 = NULL;
+
+	/* Record end of argument list. */
+	pkg_hdr->desc.len = BUF_OFFSET / sizeof(int);
+
+	if (rws_pos_en) {
+		/* Strings are appended, update location counter. */
+		pkg_hdr->desc.str_cnt = 0;
+		pkg_hdr->desc.rw_str_cnt = s_rw_cnt;
+	} else {
+		/* Strings are appended, update append counter. */
+		pkg_hdr->desc.str_cnt = s_rw_cnt;
+		pkg_hdr->desc.rw_str_cnt = 0;
+	}
+
+	pkg_hdr->desc.ro_str_cnt = s_ro_cnt;
+
+#ifdef CONFIG_CBPRINTF_PACKAGE_HEADER_STORE_CREATION_FLAGS
+	pkg_hdr->desc.pkg_flags = flags;
+#endif
+
+	/* Store strings pointer locations of read only strings. */
+	if (s_ro_cnt != 0U) {
+		for (i = 0; i < s_idx; i++) {
+			if (!(str_ptr_pos[i] & STR_POS_RO_FLAG)) {
+				continue;
+			}
+
+			uint8_t pos = str_ptr_pos[i] & STR_POS_MASK;
+
+			/* make sure it fits */
+			if ((BUF_OFFSET + 1) > len) {
+				return -ENOSPC;
+			}
+			/* store the pointer position prefix */
+			*(uint8_t *)buf = pos;
+			++buf;
+		}
+	}
+
+	/* Store strings prefixed by their pointer location. */
+	for (i = 0; i < s_idx; i++) {
+		/* Process only RW strings. */
+		if (s_ro_cnt && str_ptr_pos[i] & STR_POS_RO_FLAG) {
+			continue;
+		}
+
+		if (rws_pos_en) {
+			size = 0;
+			*(uint8_t *)buf = str_ptr_arg[i];
+			++buf;
+		} else {
+			/* retrieve the string pointer */
+			s = *(char **)(buf0 + str_ptr_pos[i] * sizeof(int));
+			/* clear the in-buffer pointer (less entropy if compressed) */
+			*(char **)(buf0 + str_ptr_pos[i] * sizeof(int)) = NULL;
+			/* find the string length including terminating '\0' */
+			size = strlen(s) + 1;
+		}
+
+		/* make sure it fits */
+		if ((BUF_OFFSET + 1 + size) > len) {
+			return -ENOSPC;
+		}
+		/* store the pointer position prefix */
+		*(uint8_t *)buf = str_ptr_pos[i];
+		++buf;
+		/* copy the string with its terminating '\0' */
+		memcpy((void *)buf, (uint8_t *)s, size);
+		buf += size;
+	}
+
+	/*
+	 * TODO: remove pointers for appended strings since they're useless.
+	 * TODO: explore leveraging same mechanism to remove alignment padding
+	 */
+
+	return BUF_OFFSET;
+
+#undef BUF_OFFSET
+#undef STR_POS_RO_FLAG
+#undef STR_POS_MASK
