--- lib/utils/cobs.c
+++ lib/utils/cobs.c
@@ -189,5 +189,77 @@

 int cobs_decoder_write(struct cobs_decoder *dec, const uint8_t *buf, size_t len)
 {
-    /* MASKED - implement this function */
-}
+	int ret;
+	uint8_t sentinel;
+
+	__ASSERT_NO_MSG(dec != NULL);
+	__ASSERT_NO_MSG(len <= INT_MAX);
+
+	sentinel = COBS_FLAG_CUSTOM_DELIMITER(dec->flags);
+
+	for (size_t i = 0; i < len; ++i) {
+		uint8_t byte = buf[i];
+
+		if (sentinel != 0x00) {
+			byte ^= sentinel;
+		}
+
+		if (dec->code_index == 0) {
+			/* Frame delimiter */
+			if (byte == 0x00) {
+				if ((dec->flags & COBS_FLAG_TRAILING_DELIMITER) != 0U) {
+					ret = dec->cb(NULL, 0, dec->cb_user_data);
+					cobs_decoder_reset(dec);
+					if (ret < 0) {
+						return ret;
+					}
+					continue;
+				}
+
+				cobs_decoder_reset(dec);
+				return -EINVAL;
+			}
+
+			/*
+			 * If the previous block ended with code < 0xFF, the
+			 * implicit zero is deferred. A new code byte signals
+			 * that the zero was present in the original data.
+			 */
+			if (dec->code < 0xFF) {
+				const uint8_t zero = 0x00;
+
+				ret = dec->cb(&zero, 1, dec->cb_user_data);
+				if (ret < 0) {
+					cobs_decoder_reset(dec);
+					return ret;
+				}
+			}
+
+			/* Start a new block */
+			dec->code = byte;
+			dec->code_index = 1;
+		} else {
+			/* A zero in a data position is invalid COBS */
+			if (byte == 0x00) {
+				cobs_decoder_reset(dec);
+				return -EINVAL;
+			}
+
+			/* Data byte for the current block */
+			ret = dec->cb(&byte, 1, dec->cb_user_data);
+			if (ret < 0) {
+				cobs_decoder_reset(dec);
+				return ret;
+			}
+
+			dec->code_index++;
+		}
+
+		/* All data bytes for this block have been consumed */
+		if (dec->code_index == dec->code) {
+			dec->code_index = 0;
+		}
+	}
+
+	return (int)len;
+}

