+++ subsys/fs/fcb/fcb_append.c
@@ -59,7 +59,72 @@
 int
 fcb_append(struct fcb *fcb, uint16_t len, struct fcb_entry *append_loc)
 {
-    /* MASKED - implement this function */
+	int rc;
+	uint8_t tmp_str[FCB_TMP_BUF_SZ];
+	int cnt;
+	uint16_t total_len;
+
+	rc = k_mutex_lock(&fcb->f_mtx, K_FOREVER);
+	if (rc) {
+		return -EINVAL;
+	}
+
+	cnt = fcb_put_len(fcb, tmp_str, len);
+	if (cnt < 0) {
+		rc = cnt;
+		goto out;
+	}
+
+	total_len = fcb_len_in_flash(fcb, cnt) +
+		    fcb_len_in_flash(fcb, len) +
+		    fcb_len_in_flash(fcb, FCB_CRC_SZ);
+
+	while (fcb->f_active.fe_elem_off + total_len >
+	       fcb->f_active.fe_sector->fs_size) {
+		rc = fcb_append_to_scratch(fcb);
+		if (rc == 0) {
+			continue;
+		}
+
+		/*
+		 * No scratch sectors available, rotate to free up space.
+		 * Must unlock first since fcb_rotate takes the mutex.
+		 */
+		k_mutex_unlock(&fcb->f_mtx);
+		rc = fcb_rotate(fcb);
+		if (rc) {
+			return rc;
+		}
+		rc = k_mutex_lock(&fcb->f_mtx, K_FOREVER);
+		if (rc) {
+			return -EINVAL;
+		}
+	}
+
+	append_loc->fe_sector = fcb->f_active.fe_sector;
+	append_loc->fe_elem_off = fcb->f_active.fe_elem_off;
+	append_loc->fe_data_off = append_loc->fe_elem_off +
+				  fcb_len_in_flash(fcb, cnt);
+	append_loc->fe_data_len = len;
+
+	/*
+	 * Pad length encoding buffer with erase value to meet alignment.
+	 */
+	(void)memset(tmp_str + cnt, fcb->f_erase_value,
+		     fcb_len_in_flash(fcb, cnt) - cnt);
+
+	rc = fcb_flash_write(fcb, append_loc->fe_sector,
+			     append_loc->fe_elem_off, tmp_str,
+			     fcb_len_in_flash(fcb, cnt));
+	if (rc) {
+		goto out;
+	}
+
+	fcb->f_active.fe_elem_off = append_loc->fe_elem_off + total_len;
+
+out:
+	k_mutex_unlock(&fcb->f_mtx);
+	return rc;
 }

