+	uint16_t decoded;
+	uint8_t code;
+
+	code = buf[0] ^ ~fcbp->f_erase_value;
+
+	if ((code & 0x80) == 0) {
+		/* 1-byte encoding */
+		decoded = code;
+	} else {
+		/* 2-byte encoding */
+		decoded = (code & 0x7f) | ((uint16_t)(buf[1] ^ ~fcbp->f_erase_value) << 7);
+	}
+
+	if (decoded > FCB_MAX_LEN) {
+		return -ENOMSG;
+	}
+
+	*len = decoded;
+	return (code & 0x80) == 0 ? 1 : 2;
 }

