--- subsys/fs/fcb/fcb.c
+++ subsys/fs/fcb/fcb.c
@@ -305,7 +305,51 @@
  */
 int fcb_offset_last_n(struct fcb *fcbp, uint8_t entries, struct fcb_entry *last_n_entry)
 {
-    /* MASKED - implement this function */
+	struct fcb_entry loc;
+	int rc;
+	uint16_t count = 0;
+	uint16_t target;
+
+	rc = k_mutex_lock(&fcbp->f_mtx, K_FOREVER);
+	if (rc != 0) {
+		return -EINVAL;
+	}
+
+	/* Count all entries */
+	memset(&loc, 0, sizeof(loc));
+	while (1) {
+		rc = fcb_getnext_nolock(fcbp, &loc);
+		if (rc != 0) {
+			break;
+		}
+		count++;
+	}
+
+	/* If no entries or nothing requested, report none */
+	if (count == 0 || entries == 0) {
+		k_mutex_unlock(&fcbp->f_mtx);
+		return -ENOENT;
+	}
+
+	/* Calculate target: entry that is `entries` from the end */
+	if (entries >= count) {
+		target = 0;
+	} else {
+		target = count - entries;
+	}
+
+	/* Walk to the target entry */
+	memset(last_n_entry, 0, sizeof(*last_n_entry));
+	for (uint16_t i = 0; i <= target; i++) {
+		rc = fcb_getnext_nolock(fcbp, last_n_entry);
+		if (rc != 0) {
+			k_mutex_unlock(&fcbp->f_mtx);
+			return rc;
+		}
+	}
+
+	k_mutex_unlock(&fcbp->f_mtx);
+	return 0;
 }

