+	psa_status_t status;
+	uint8_t hash[PSA_HASH_LENGTH(PSA_ALG_SHA_256)];
+	size_t hash_len;
+	size_t remain;
+	int rc;
+
+	if (fa == NULL || fac == NULL) {
+		return -EINVAL;
+	}
+
+	if (fac->match == NULL || fac->clen == 0 ||
+	    fac->off >= fa->fa_size ||
+	    fac->rbuf == NULL || fac->rblen == 0) {
+		return -EINVAL;
+	}
+
+	if (fac->off + fac->clen > fa->fa_size) {
+		return -EINVAL;
+	}
+
+	op = psa_hash_operation_init();
+	status = psa_hash_setup(&op, PSA_ALG_SHA_256);
+	if (status != PSA_SUCCESS) {
+		return -EIO;
+	}
+
+	remain = fac->clen;
+	while (remain > 0) {
+		size_t chunk = (remain < fac->rblen) ? remain : fac->rblen;
+
+		rc = flash_area_read(fa, fac->off + (fac->clen - remain),
+				     fac->rbuf, chunk);
+		if (rc != 0) {
+			psa_hash_abort(&op);
+			return rc;
+		}
+
+		status = psa_hash_update(&op, fac->rbuf, chunk);
+		if (status != PSA_SUCCESS) {
+			psa_hash_abort(&op);
+			return -EIO;
+		}
+
+		remain -= chunk;
+	}
+
+	status = psa_hash_finish(&op, hash, sizeof(hash), &hash_len);
+	if (status != PSA_SUCCESS) {
+		return -EIO;
+	}
+
+	if (memcmp(hash, fac->match, sizeof(hash)) != 0) {
+		return -EBADMSG;
+	}
+
+	return 0;
 }

