--- subsys/gnss/rtk/protocol/rtcm3.c
+++ subsys/gnss/rtk/protocol/rtcm3.c
@@ -31,5 +31,46 @@
 int gnss_rtk_decoder_frame_get(uint8_t *buf, size_t buf_len,
 			       uint8_t **data, size_t *data_len)
 {
-    /* MASKED - implement this function */
+	size_t i;
+
+	if (buf == NULL || data == NULL || data_len == NULL) {
+		return -ENOENT;
+	}
+
+	/* Need at least the minimum frame size */
+	if (buf_len < RTCM3_FRAME_OVERHEAD) {
+		return -ENOENT;
+	}
+
+	/* Scan buffer for a valid RTCM3 frame */
+	for (i = 0; i <= buf_len - RTCM3_FRAME_OVERHEAD; i++) {
+		uint16_t hdr;
+		uint16_t payload_len;
+		size_t frame_len;
+
+		if (buf[i] != RTCM3_SYNC_BYTE) {
+			continue;
+		}
+
+		/* Parse 2-byte big-endian header for payload length */
+		hdr = sys_get_be16(&buf[i + RTCM3_FRAME_SYNC_SZ]);
+		payload_len = RTCM3_FRAME_PAYLOAD_SZ(hdr);
+		frame_len = RTCM3_FRAME_SZ(payload_len);
+
+		/* Verify complete frame is in the buffer */
+		if (frame_len > buf_len - i) {
+			continue;
+		}
+
+		/* Validate CRC-24Q (returns 0 when checksum matches) */
+		if (crc24q_rtcm3(&buf[i], frame_len) != 0) {
+			continue;
+		}
+
+		*data = &buf[i];
+		*data_len = frame_len;
+		return 0;
+	}
+
+	return -ENOENT;
 }

