-    /* MASKED - implement this function */
+	uint8_t c;
+	size_t written = 0;
+
+	if (hexlen & 1U) {
+		return 0;
+	}
+
+	if (buflen < (hexlen / 2U)) {
+		return 0;
+	}
+
+	while (hexlen > 0U) {
+		if (char2hex(hex[0], &c) < 0) {
+			return 0;
+		}
+		buf[written] = c << 4;
+		if (char2hex(hex[1], &c) < 0) {
