--- lib/net_buf/buf.c
+++ lib/net_buf/buf.c
@@ -712,5 +712,45 @@

 size_t net_buf_data_match(const struct net_buf *buf, size_t offset, const void *data, size_t len)
 {
-    /* MASKED - implement this function */
-}
+	const struct net_buf *frag;
+	size_t matched = 0;
+
+	if (buf == NULL || data == NULL) {
+		return 0;
+	}
+
+	frag = buf;
+
+	/* Skip fragments until we reach the offset */
+	while (frag != NULL && offset >= frag->len) {
+		offset -= frag->len;
+		frag = frag->frags;
+	}
+
+	if (frag == NULL) {
+		return 0;
+	}
+
+	/* Compare bytes across fragments */
+	while (frag != NULL && len > 0) {
+		size_t to_compare = min(len, frag->len - offset);
+		const uint8_t *frag_data = frag->data + offset;
+		const uint8_t *input_data = (const uint8_t *)data + matched;
+
+		if (memcmp(frag_data, input_data, to_compare) != 0) {
+			/* Find the exact mismatch position */
+			for (size_t i = 0; i < to_compare; i++) {
+				if (frag_data[i] != input_data[i]) {
+					return matched + i;
+				}
+			}
+		}
+
+		matched += to_compare;
+		len -= to_compare;
+		frag = frag->frags;
+		offset = 0;
+	}
+
+	return matched;
+}

