--- subsys/net/ip/net_timeout.c
+++ subsys/net/ip/net_timeout.c
@@ -78,5 +78,67 @@
 uint32_t net_timeout_evaluate(struct net_timeout *timeout,
 			      uint32_t now)
 {
-    /* MASKED - implement this function */
+	uint32_t delta = now - timeout->timer_start;
+	uint64_t total;
+	bool wraps_consumed = false;
+
+	total = (uint64_t)timeout->timer_timeout +
+		(uint64_t)timeout->wrap_counter * NET_TIMEOUT_MAX_VALUE;
+
+	if (delta >= total) {
+		return 0;
+	}
+
+	/* Consume full wraps that have elapsed.  Wraps count down the
+	 * multiples of NET_TIMEOUT_MAX_VALUE; the fractional timer_timeout
+	 * is only reached after all wraps are consumed.
+	 */
+	while (timeout->wrap_counter > 0 &&
+	       delta >= NET_TIMEOUT_MAX_VALUE) {
+		timeout->wrap_counter--;
+		delta -= NET_TIMEOUT_MAX_VALUE;
+		wraps_consumed = true;
+	}
+
+	if (wraps_consumed) {
+		uint64_t remaining;
+
+		remaining = (uint64_t)timeout->timer_timeout +
+			    (uint64_t)timeout->wrap_counter *
+			    NET_TIMEOUT_MAX_VALUE;
+		remaining -= delta;
+
+		if (remaining == 0) {
+			return 0;
+		}
+
+		timeout->timer_start = now;
+		timeout->wrap_counter =
+			remaining / NET_TIMEOUT_MAX_VALUE;
+		timeout->timer_timeout =
+			remaining % NET_TIMEOUT_MAX_VALUE;
+
+		if (timeout->timer_timeout == 0 &&
+		    timeout->wrap_counter > 0) {
+			timeout->timer_timeout = NET_TIMEOUT_MAX_VALUE;
+			timeout->wrap_counter--;
+		}
+
+		if (timeout->wrap_counter > 0) {
+			return NET_TIMEOUT_MAX_VALUE;
+		}
+
+		return timeout->timer_timeout;
+	}
+
+	/* No wraps consumed. */
+	if (timeout->wrap_counter > 0) {
+		return NET_TIMEOUT_MAX_VALUE - delta;
+	}
+
+	if (delta >= timeout->timer_timeout) {
+		return 0;
+	}
+
+	return timeout->timer_timeout - delta;
 }

