 {
-    /* MASKED - implement this function */
-}
+	osEvent ret;
+	int key;
+	int32_t sig;
+	osThreadDef_t *thread_def;
+	k_timeout_t timeout;
+	bool forever;
+
+	if (k_is_in_isr()) {
+		ret.status = osErrorISR;
+		ret.value.signals = 0;
+		return ret;
+	}
+
+	if (signals != 0) {
+		if ((signals & 0x80000000) || (signals > MAX_VALID_SIGNAL_VAL)) {
+			ret.status = osErrorValue;
+			ret.value.signals = 0;
+			return ret;
+		}
+	}
+
+	thread_def = (osThreadDef_t *)k_thread_other_custom_data_get(
+						k_current_get());
+
+	/* Quick check for signals already pending. */
+	key = irq_lock();
+	if (signals == 0) {
+		sig = thread_def->signal_results;
+		if (sig != 0) {
+			thread_def->signal_results = 0;
+			irq_unlock(key);
+			ret.status = osEventSignal;
+			ret.value.signals = sig;
+			return ret;
+		}
+	} else {
+		sig = thread_def->signal_results;
+		if ((sig & signals) == signals) {
+			thread_def->signal_results = sig & ~signals;
+			irq_unlock(key);
+			ret.status = osEventSignal;
+			ret.value.signals = sig;
+			return ret;
+		}
+	}
+	irq_unlock(key);
+
+	if (millisec == 0U) {
+		ret.status = osEventTimeout;
+		ret.value.signals = 0;
+		return ret;
+	}
+
+	forever = (millisec == osWaitForever);
+	timeout = forever ? K_FOREVER : K_MSEC(millisec);
+
+	/*
+	 * Re-arm the poll signal.  We hold irq_lock across the check and
+	 * k_poll_signal_init so that a concurrent osSignalSet cannot
+	 * raise the poll signal between us seeing signal_results and
+	 * resetting the signal state.
+	 */
+	key = irq_lock();
+	if (signals == 0) {
+		sig = thread_def->signal_results;
+		if (sig != 0) {
+			thread_def->signal_results = 0;
+			irq_unlock(key);
+			ret.status = osEventSignal;
+			ret.value.signals = sig;
+			return ret;
+		}
+	} else {
+		sig = thread_def->signal_results;
+		if ((sig & signals) == signals) {
+			thread_def->signal_results = sig & ~signals;
+			irq_unlock(key);
+			ret.status = osEventSignal;
+			ret.value.signals = sig;
+			return ret;
+		}
+	}
+
+	k_poll_signal_init(thread_def->poll_signal);
+	irq_unlock(key);
+
+	k_poll_event_init(thread_def->poll_event, K_POLL_TYPE_SIGNAL,
+			  K_POLL_MODE_NOTIFY_ONLY, thread_def->poll_signal);
+
+	while (1) {
+		int poll_ret = k_poll(thread_def->poll_event, 1, timeout);
+
+		if (poll_ret == -EAGAIN) {
+			ret.status = osEventTimeout;
+			ret.value.signals = 0;
+			return ret;
+		}
+
+		/* Signal raised, check if our condition is met. */
+		key = irq_lock();
+		if (signals == 0) {
+			sig = thread_def->signal_results;
+			if (sig != 0) {
+				thread_def->signal_results = 0;
+				irq_unlock(key);
+				ret.status = osEventSignal;
+				ret.value.signals = sig;
+				return ret;
+			}
+		} else {
+			sig = thread_def->signal_results;
+			if ((sig & signals) == signals) {
+				thread_def->signal_results = sig & ~signals;
+				irq_unlock(key);
+				ret.status = osEventSignal;
+				ret.value.signals = sig;
+				return ret;
+			}
+		}
+		irq_unlock(key);
+
+		/* Condition not met.  For a finite timeout we're done. */
+		if (!forever) {
+			ret.status = osEventTimeout;
+			ret.value.signals = 0;
+			return ret;
+		}
+
+		/* Re-arm for the next wait. */
+		key = irq_lock();
+		k_poll_signal_init(thread_def->poll_signal);
+		irq_unlock(key);
+
+		k_poll_event_init(thread_def->poll_event, K_POLL_TYPE_SIGNAL,
+				  K_POLL_MODE_NOTIFY_ONLY,
+				  thread_def->poll_signal);
+	}
+}

