@@ -86,5 +86,66 @@
  */
 uint32_t osThreadFlagsWait(uint32_t flags, uint32_t options, uint32_t timeout)
 {
-    /* MASKED - implement this function */
+	struct cmsis_rtos_thread_cb *tid;
+	unsigned int key;
+	uint32_t ret_flags;
+	int ret;
+
+	if ((flags == 0U) || (flags & 0x80000000U)) {
+		return osFlagsErrorParameter;
+	}
+
+	if (k_is_in_isr()) {
+		return osFlagsErrorUnknown;
+	}
+
+	tid = (struct cmsis_rtos_thread_cb *)osThreadGetId();
+	if (tid == NULL) {
+		return osFlagsErrorUnknown;
+	}
+
+	key = irq_lock();
+
+	for (;;) {
+		/* Check if the requested flags are already set */
+		if (options & osFlagsWaitAll) {
+			if ((tid->signal_results & flags) == flags) {
+				break;
+			}
+		} else {
+			if ((tid->signal_results & flags) != 0U) {
+				break;
+			}
+		}
+
+		/* Flags not yet set */
+		if (timeout == 0U) {
+			irq_unlock(key);
+			return osFlagsErrorTimeout;
+		}
+
+		/* Reset poll signal and event for re-use */
+		tid->poll_event.state = K_POLL_STATE_NOT_READY;
+		tid->poll_signal.signaled = 0U;
+
+		irq_unlock(key);
+
+		ret = k_poll(&tid->poll_event, 1,
+			     (timeout == osWaitForever) ? K_FOREVER : K_TICKS(timeout));
+
+		if (ret == -EAGAIN) {
+			return osFlagsErrorTimeout;
+		}
+
+		key = irq_lock();
+	}
+
+	/* Return flags (before clearing, per CMSIS spec) */
+	ret_flags = tid->signal_results;
+	if (!(options & osFlagsNoClear)) {
+		tid->signal_results &= ~flags;
+	}
+	irq_unlock(key);
+
+	return ret_flags;
 }

