--- subsys/ipc/ipc_service/lib/pbuf.c
+++ subsys/ipc/ipc_service/lib/pbuf.c
@@ -221,7 +221,82 @@

 int pbuf_read(struct pbuf *pb, char *buf, uint16_t len)
 {
-    /* MASKED - implement this function */
+	if (pb == NULL) {
+		return -EINVAL;
+	}
+
+	/* Invalidate wr_idx to get latest write position from the writer. */
+	sys_cache_data_invd_range((void *)(pb->cfg->wr_idx_loc), sizeof(*(pb->cfg->wr_idx_loc)));
+	barrier_sync_synchronize();
+
+	uint8_t *const data_loc = pb->cfg->data_loc;
+	const uint32_t blen = pb->cfg->len;
+	uint32_t wr_idx = *(pb->cfg->wr_idx_loc);
+	uint32_t rd_idx = pb->data.rd_idx;
+
+	/* rd_idx must always be aligned. */
+	__ASSERT_NO_MSG(IS_PTR_ALIGNED_BYTES(rd_idx, _PBUF_IDX_SIZE));
+	/* wr_idx shall always be aligned, but its value is received from the writer.
+	 * Can not assert.
+	 */
+	if (!IS_PTR_ALIGNED_BYTES(wr_idx, _PBUF_IDX_SIZE)) {
+		return -EINVAL;
+	}
+
+	/* Check if there is at least a packet length header available. */
+	uint32_t occupied = idx_occupied(blen, wr_idx, rd_idx);
+
+	if (occupied < PBUF_PACKET_LEN_SZ) {
+		return 0;
+	}
+
+	/* Invalidate and read packet length from the header. */
+	sys_cache_data_invd_range(&data_loc[rd_idx], PBUF_PACKET_LEN_SZ);
+	barrier_sync_synchronize();
+
+	uint16_t plen = sys_get_be16(&data_loc[rd_idx]);
+
+	/* Check if the full message is ready. */
+	if (occupied < PBUF_PACKET_LEN_SZ + plen) {
+		return 0;
+	}
+
+	/* If buf is NULL, return the message length without consuming it. */
+	if (buf == NULL) {
+		return plen;
+	}
+
+	/* Check if the provided buffer is large enough. */
+	if (len < plen) {
+		return -ENOMEM;
+	}
+
+	/* Advance past the header to the data start. */
+	rd_idx = idx_wrap(blen, rd_idx + PBUF_PACKET_LEN_SZ);
+
+	/* Read data, handling wrap around. */
+	uint32_t tail = MIN(plen, blen - rd_idx);
+
+	sys_cache_data_invd_range(&data_loc[rd_idx], tail);
+	barrier_sync_synchronize();
+	memcpy(buf, &data_loc[rd_idx], tail);
+
+	if (plen > tail) {
+		/* Read remaining data from buffer front. */
+		sys_cache_data_invd_range(&data_loc[0], plen - tail);
+		barrier_sync_synchronize();
+		memcpy(buf + tail, &data_loc[0], plen - tail);
+	}
+
+	/* Update rd_idx past the consumed packet (padded to alignment). */
+	uint32_t final_rd_idx = idx_wrap(blen, ROUND_UP(rd_idx + plen, _PBUF_IDX_SIZE));
+
+	pb->data.rd_idx = final_rd_idx;
+	*(pb->cfg->rd_idx_loc) = final_rd_idx;
+	barrier_sync_synchronize();
+	sys_cache_data_flush_range((void *)pb->cfg->rd_idx_loc, sizeof(*(pb->cfg->rd_idx_loc)));
+
+	return plen;
 }

