patch:
--- subsys/pm/device.c
+++ subsys/pm/device.c
@@ -437,5 +437,42 @@
 int pm_device_driver_deinit(const struct device *dev,
 			    pm_device_action_cb_t action_cb)
 {
-    /* MASKED - implement this function */
-}
+	struct pm_device_base *pm = dev->pm_base;
+	int rc;
+
+	/* Work only needs to be performed if the device is powered */
+	if (!pm_device_is_powered(dev)) {
+		return 0;
+	}
+
+	/* If device has no PM structure */
+	if (pm == NULL) {
+		/* Reverse of init: first suspend, then turn off */
+		rc = action_cb(dev, PM_DEVICE_ACTION_SUSPEND);
+		if ((rc < 0) && (rc != -ENOTSUP)) {
+			return rc;
+		}
+
+		return action_cb(dev, PM_DEVICE_ACTION_TURN_OFF);
+	}
+
+	/* If device is currently in the ACTIVE state, suspend it first */
+	if (pm->state == PM_DEVICE_STATE_ACTIVE) {
+		rc = action_cb(dev, PM_DEVICE_ACTION_SUSPEND);
+		if ((rc < 0) && (rc != -ENOTSUP)) {
+			return rc;
+		}
+		pm->state = PM_DEVICE_STATE_SUSPENDED;
+	}
+
+	/* Run power-down logic */
+	rc = action_cb(dev, PM_DEVICE_ACTION_TURN_OFF);
+	if ((rc < 0) && (rc != -ENOTSUP)) {
+		return rc;
+	}
+
+	/* Device is now in the OFF state */
+	pm->state = PM_DEVICE_STATE_OFF;
+
+	return 0;
+}

