patch:
--- lib/utils/rb.c
+++ lib/utils/rb.c
@@ -371,7 +371,134 @@

 void rb_remove(struct rbtree *tree, struct rbnode *node)
 {
-    /* MASKED - implement this function */
+	struct rbnode *child;
+	struct rbnode *parent;
+	bool node_black;
+
+	if (tree->root == NULL) {
+		return;
+	}
+
+#ifdef CONFIG_MISRA_SANE
+	struct rbnode **stack = &tree->iter_stack[0];
+#else
+	struct rbnode *stack[tree->max_depth + 3];
+#endif
+
+	int stacksz = find_and_stack(tree, node, stack);
+
+	if (stack[stacksz - 1] != node) {
+		return;
+	}
+
+	/* Case: node has two children.  Find in-order successor (minimum
+	 * of right subtree), splice it out, then replace node with it.
+	 */
+	if ((get_child(node, 0U) != NULL) && (get_child(node, 1U) != NULL)) {
+		struct rbnode *succ = get_child(node, 1U);
+		struct rbnode *node_l = get_child(node, 0U);
+		struct rbnode *node_r = get_child(node, 1U);
+		uint8_t node_col = get_color(node);
+		int ssz = stacksz;
+
+		/* Extend the stack to the successor */
+		stack[ssz] = succ;
+		ssz++;
+		while (get_child(succ, 0U) != NULL) {
+			succ = get_child(succ, 0U);
+			stack[ssz] = succ;
+			ssz++;
+		}
+
+		/* Save successor's info before detaching */
+		struct rbnode *sp = stack[ssz - 2];
+		uint8_t succ_side = get_side(sp, succ);
+		struct rbnode *sr = get_child(succ, 1U);
+		bool succ_black = is_black(succ);
+
+		/* Detach successor, replacing it with its right child */
+		set_child(sp, succ_side, sr);
+
+		/* Fix black-height if successor was black */
+		if (succ_black) {
+			if (sr != NULL) {
+				/* succ had a single child which must be red;
+				 * recolor it to black.
+				 */
+				set_color(sr, BLACK);
+			} else {
+				/* succ was a black leaf: use null_node trick */
+				struct rbnode null_node;
+
+				stack[ssz - 1] = &null_node;
+				fix_missing_black(stack, ssz, &null_node);
+			}
+		}
+
+		/* fix_missing_black may have rotated the root */
+		tree->root = stack[0];
+
+		/* Re-find node in the (potentially rebalanced) tree */
+		stacksz = find_and_stack(tree, node, stack);
+		parent = (stacksz > 1) ? stack[stacksz - 2] : NULL;
+
+		/* Replace node with successor */
+		if (parent != NULL) {
+			set_child(parent, get_side(parent, node), succ);
+		} else {
+			tree->root = succ;
+		}
+
+		set_child(succ, 0U, node_l);
+		if (sp == node) {
+			set_child(succ, 1U, sr);
+		} else {
+			set_child(succ, 1U, node_r);
+		}
+		set_color(succ, node_col);
+
+		return;
+	}
+
+	/* Fallthrough: node has 0 or 1 child */
+	child = get_child(node, 0U);
+	if (child == NULL) {
+		child = get_child(node, 1U);
+	}
+
+	parent = (stacksz > 1) ? stack[stacksz - 2] : NULL;
+	node_black = is_black(node);
+
+	if (child != NULL) {
+		/* One child.  For a valid tree, if node was black then
+		 * child must be red, so we just recolor.
+		 */
+		if (parent != NULL) {
+			set_child(parent, get_side(parent, node), child);
+		} else {
+			tree->root = child;
+		}
+
+		if (node_black) {
+			set_color(child, BLACK);
+		}
+	} else {
+		/* Leaf node */
+		if (parent != NULL) {
+			if (node_black) {
+				struct rbnode null_node;
+
+				set_child(parent, get_side(parent, node), &null_node);
+				stack[stacksz - 1] = &null_node;
+				fix_missing_black(stack, stacksz, &null_node);
+				tree->root = stack[0];
+			} else {
+				set_child(parent, get_side(parent, node), NULL);
+			}
+		} else {
+			tree->root = NULL;
+		}
+	}
 }

