+	if (wr_idx < rd_idx) {
+		/* Writer behind reader: free space is the gap between them. */
+		space = (rd_idx > wr_idx + FREE_SPACE_DISTANCE)
+			? (rd_idx - wr_idx - FREE_SPACE_DISTANCE) : 0;
+	} else {
+		space = pblen - wr_idx;
+	}
