+	/*
+	 * The align parameter may encode a "rewind" bit: when align is not
+	 * a pure power of two, the least significant set bit is the rewind
+	 * amount and the remaining upper bits form the true alignment.
+	 * The returned pointer satisfies (ptr + rewind) % real_align == 0.
+	 */
+	size_t rew = LSB_GET(align);
+
+	if (rew != align) {
+		align -= rew;
+	} else {
+		rew = 0;
+	}
+
+	__ASSERT((align & (align - 1)) == 0, "align must be a power of 2");
+
+	if (align <= chunk_header_bytes(h)) {
+		return sys_heap_alloc(heap, bytes);
+	}
+
+	/*
+	 * Overallocate by (align + chunk_header_bytes(h)) to guarantee we
+	 * can find a suitably aligned address within the chunk and still
+	 * have enough room left after splitting off the alignment gap.
+	 */
+	chunksz_t chunk_sz = bytes_to_chunksz(h, bytes, align + chunk_header_bytes(h));
+	chunkid_t c = alloc_chunk(h, chunk_sz);
+
+	if (c == 0U) {
+		return NULL;
+	}
+
+	/* Find the aligned boundary then apply the rewind (if any) */
+	uintptr_t chunk_mem_ptr = (uintptr_t)chunk_mem(h, c);
+	uintptr_t aligned_addr = ROUND_UP(chunk_mem_ptr, align) - rew;
+
+	/*
+	 * If the rewind pushes the pointer before the chunk's data start,
+	 * advance to the next alignment boundary.  This guarantees that
+	 * aligned_addr always falls within the allocated chunk.
+	 */
+	if (aligned_addr < chunk_mem_ptr) {
+		aligned_addr += align;
+	}
+
+	/*
+	 * Find the chunk ID closest to the aligned address.  On big heaps
+	 * (8-byte header) this is exact; on small heaps (4-byte header) the
+	 * returned chunk may have its data starting slightly before the
+	 * aligned address, in which case the difference is tracked as an
+	 * alignment gap via mem_align_gap().
+	 */
+	chunkid_t aligned_c = mem_to_chunkid(h, (void *)aligned_addr);
+
+	/* Split off left gap chunk (if any) and free it */
+	if (aligned_c > c) {
+		split_chunks(h, c, aligned_c);
+		free_list_add(h, c);
+		c = aligned_c;
+	}
+
+	/* Compute the actual gap between chunk_mem(c) and the returned pointer */
+	size_t gap = aligned_addr - (uintptr_t)chunk_mem(h, c);
+
+	/* Split off excess on the right (if any) and free it */
+	chunksz_t needed_sz = bytes_to_chunksz(h, bytes, gap);
+
+	if (chunk_size(h, c) > needed_sz) {
+		split_chunks(h, c, c + needed_sz);
+		free_list_add(h, c + needed_sz);
+	}
+
+	set_chunk_used(h, c, true);
+	if (SYS_HEAP_HARDENING_FULL) {
+		set_chunk_canary(h, c);
+	}
+
+	mem = (void *)aligned_addr;
+
+#ifdef CONFIG_SYS_HEAP_RUNTIME_STATS
+	increase_allocated_bytes(h, chunk_usable_bytes(h, c));
+#endif
+
+#ifdef CONFIG_SYS_HEAP_LISTENER
+	heap_listener_notify_alloc(HEAP_ID_FROM_POINTER(heap), mem,
+				   chunk_usable_bytes(h, c) - gap);
+#endif
+
+	IF_ENABLED(CONFIG_MSAN, (__msan_allocated_memory(mem, bytes)));
+	return mem;
