+	/* Chunk 0 is a used marker chunk covering the metadata area.
+	 * Its header aliases chunk0_hdr[] in the struct.  LEFT_SIZE is
+	 * irrelevant for the first chunk.
+	 */
+	set_chunk_size(h, 0, meta_units);
+	set_chunk_used(h, 0, true);
+
+	if (end_chunk > meta_units) {
+		chunksz_t free_sz = end_chunk - meta_units;
+
+		/* Free chunk right after the metadata */
+		set_left_chunk_size(h, meta_units, meta_units);
+		set_chunk_size(h, meta_units, free_sz);
+		set_chunk_used(h, meta_units, false);
+
+		/* Sentinel at the end of the arena */
+		set_left_chunk_size(h, end_chunk, free_sz);
+		set_chunk_size(h, end_chunk, 0U);
