patch:
--- drivers/usb/device/usb_dc_dw.c
+++ drivers/usb/device/usb_dc_dw.c
@@ -1230,7 +1230,89 @@
 int usb_dc_ep_read_wait(uint8_t ep, uint8_t *data, uint32_t max_data_len,
 			uint32_t *read_bytes)
 {
-    /* MASKED - implement this function */
+	struct usb_dwc2_reg *const base = usb_dw_cfg.base;
+	uint8_t ep_idx = USB_EP_GET_IDX(ep);
+	uint32_t read_count;
+	unsigned int key;
+	uint32_t i;
+
+	if (!usb_dw_ctrl.attached || !usb_dw_ep_is_valid(ep)) {
+		LOG_ERR("Not attached / Invalid endpoint: EP 0x%x", ep);
+		return -EINVAL;
+	}
+
+	/* Check if OUT ep */
+	if (USB_EP_GET_DIR(ep) != USB_EP_DIR_OUT) {
+		LOG_ERR("Wrong endpoint direction");
+		return -EINVAL;
+	}
+
+	/* Check if ep enabled */
+	if (!usb_dw_ep_is_enabled(ep)) {
+		return -EINVAL;
+	}
+
+	read_count = usb_dw_ctrl.out_ep_ctrl[ep_idx].data_len;
+
+	LOG_DBG("EP 0x%02x, %u bytes available, max %u", ep, read_count,
+		max_data_len);
+
+	/* When both buffer and max data to read are zero, just return the
+	 * number of bytes available for read.
+	 */
+	if (!data && !max_data_len) {
+		if (read_bytes) {
+			*read_bytes = read_count;
+		}
+
+		return 0;
+	}
+
+	if (data == NULL) {
+		return -EINVAL;
+	}
+
+	if (read_count == 0U) {
+		if (read_bytes) {
+			*read_bytes = 0U;
+		}
+
+		return 0;
+	}
+
+	if (read_count > max_data_len) {
+		read_count = max_data_len;
+	}
+
+	/* Read data from the global RX FIFO, locking interrupts to prevent
+	 * concurrent register access during FIFO operations.
+	 */
+	key = irq_lock();
+
+	for (i = 0U; i < read_count; i += 4U) {
+		uint32_t val = USB_DW_EP_FIFO(base, 0);
+
+		data[i] = val & 0xFF;
+		if (i + 1 < read_count) {
+			data[i + 1] = (val >> 8) & 0xFF;
+		}
+		if (i + 2 < read_count) {
+			data[i + 2] = (val >> 16) & 0xFF;
+		}
+		if (i + 3 < read_count) {
+			data[i + 3] = (val >> 24) & 0xFF;
+		}
+	}
+
+	irq_unlock(key);
+
+	usb_dw_ctrl.out_ep_ctrl[ep_idx].data_len -= read_count;
+
+	if (read_bytes) {
+		*read_bytes = read_count;
+	}
+
+	return 0;
 }

