--- subsys/usb/host/usbh_desc.c
+++ subsys/usb/host/usbh_desc.c
@@ -176,5 +176,58 @@

 const void *usbh_desc_get_next_function(const void *const desc)
 {
-    /* MASKED - implement this function */
-}
+	const struct usb_desc_header *head;
+	uint8_t iface_start = 0;
+	uint8_t iface_count = 0;
+	bool skip_iface_range = false;
+
+	if (!usbh_desc_is_valid(desc, sizeof(struct usb_desc_header), 0)) {
+		return NULL;
+	}
+
+	/* Determine the interface range belonging to the current function */
+	const struct usb_desc_header *const hdr = desc;
+	if (hdr->bDescriptorType == USB_DESC_INTERFACE_ASSOC) {
+		const struct usb_association_descriptor *iad = desc;
+
+		iface_start = iad->bFirstInterface;
+		iface_count = iad->bInterfaceCount;
+		skip_iface_range = true;
+	} else if (hdr->bDescriptorType == USB_DESC_INTERFACE) {
+		const struct usb_if_descriptor *iface = desc;
+
+		iface_start = iface->bInterfaceNumber;
+		iface_count = 1U;
+		skip_iface_range = true;
+	}
+
+	/* Skip past the current descriptor */
+	head = usbh_desc_get_next(desc);
+	if (head == NULL) {
+		return NULL;
+	}
+
+	/* Walk through the descriptor list to find the next function */
+	while (head != NULL) {
+		if (head->bDescriptorType == USB_DESC_INTERFACE_ASSOC) {
+			return head;
+		}
+
+		if (head->bDescriptorType == USB_DESC_INTERFACE) {
+			const struct usb_if_descriptor *iface = (const void *)head;
+
+			if (!skip_iface_range ||
+			    iface->bInterfaceNumber < iface_start ||
+			    iface->bInterfaceNumber >= iface_start + iface_count) {
+
+				if (iface->bAlternateSetting == 0U) {
+					return head;
+				}
+			}
+		}
+
+		head = usbh_desc_get_next(head);
+	}
+
+	return NULL;
+}

