patch:
--- subsys/usb/host/usbh_ch9.c
+++ subsys/usb/host/usbh_ch9.c
@@ -55,7 +55,66 @@
 		   const uint16_t wLength,
 		   struct net_buf *const buf)
 {
-    /* MASKED - implement this function */
+	struct usb_setup_packet setup;
+	struct uhc_transfer *xfer;
+	uint8_t ep;
+	int ret;
+
+	/* Endpoint direction matches the request direction bit */
+	ep = bmRequestType & 0x80U;
+
+	/* Build setup packet in USB little-endian wire format */
+	setup.bmRequestType = bmRequestType;
+	setup.bRequest = bRequest;
+	setup.wValue = sys_cpu_to_le16(wValue);
+	setup.wIndex = sys_cpu_to_le16(wIndex);
+	setup.wLength = sys_cpu_to_le16(wLength);
+
+	/* Allocate a UHC transfer for this control request */
+	xfer = usbh_xfer_alloc(udev, ep, ch9_req_cb, NULL);
+	if (xfer == NULL) {
+		return -ENOMEM;
+	}
+
+	/* Copy the 8-byte setup packet into the transfer */
+	memcpy(xfer->setup_pkt, &setup, sizeof(struct usb_setup_packet));
+
+	/* Attach data buffer, if any */
+	if (buf != NULL) {
+		ret = usbh_xfer_buf_add(udev, xfer, buf);
+		if (ret != 0) {
+			usbh_xfer_free(udev, xfer);
+			return ret;
+		}
+	}
+
+	/* Apply no_status flag if configured by the caller */
+	xfer->no_status = ctrl_req_no_status;
+
+	/* Reset completion semaphore before enqueue */
+	k_sem_reset(&ch9_req_sync);
+
+	/* Submit the transfer to the UHC */
+	ret = usbh_xfer_enqueue(udev, xfer);
+	if (ret != 0) {
+		usbh_xfer_free(udev, xfer);
+		return ret;
+	}
+
+	/* Wait for transfer completion */
+	if (k_sem_take(&ch9_req_sync, K_MSEC(SETUP_REQ_TIMEOUT)) != 0) {
+		/* Transfer timed out, attempt to cancel */
+		ret = usbh_xfer_dequeue(udev, xfer);
+		if (ret != 0) {
+			/* Dequeue failed, free the transfer manually */
+			usbh_xfer_free(udev, xfer);
+		}
+
+		return -ETIMEDOUT;
+	}
+
+	/* Return the transfer result from the completion callback */
+	return xfer->err;
 }

