--- lib/uuid/uuid.c
+++ lib/uuid/uuid.c
@@ -154,7 +154,51 @@

 int uuid_from_string(const char data[UUID_STR_LEN], struct uuid *out)
 {
-    /* MASKED - implement this function */
+	if ((data == NULL) || (out == NULL)) {
+		return -EINVAL;
+	}
+
+	if (strnlen(data, UUID_STR_LEN) != UUID_STR_LEN - 1U) {
+		return -EINVAL;
+	}
+
+	uint8_t byte_val = 0U;
+	unsigned int byte_idx = 0U;
+	bool high_nibble = true;
+
+	for (unsigned int i = 0U; i < UUID_STR_LEN - 1U; i++) {
+		if (should_be_hyphen(i)) {
+			if (data[i] != '-') {
+				return -EINVAL;
+			}
+			continue;
+		}
+
+		char c = data[i];
+		uint8_t nibble;
+
+		if ((c >= '0') && (c <= '9')) {
+			nibble = (uint8_t)(c - '0');
+		} else if ((c >= 'a') && (c <= 'f')) {
+			nibble = (uint8_t)(c - 'a' + 10U);
+		} else if ((c >= 'A') && (c <= 'F')) {
+			nibble = (uint8_t)(c - 'A' + 10U);
+		} else {
+			return -EINVAL;
+		}
+
+		if (high_nibble) {
+			byte_val = (uint8_t)(nibble << 4U);
+			high_nibble = false;
+		} else {
+			byte_val |= nibble;
+			out->val[byte_idx] = byte_val;
+			byte_idx++;
+			high_nibble = true;
+		}
+	}
+
+	return 0;
 }

