--- subsys/shell/shell_history.c
+++ subsys/shell/shell_history.c
@@ -71,7 +71,44 @@
 void z_shell_history_put(struct shell_history *history, uint8_t *line,
 			 size_t len)
 {
-    /* MASKED - implement this function */
+	struct shell_history_item *h_item;
+	sys_dnode_t *last;
+
+	if (len == 0) {
+		return;
+	}
+
+	/* Do not store the same command as the last one. */
+	if (!sys_dlist_is_empty(&history->list)) {
+		last = sys_dlist_peek_tail(&history->list);
+		h_item = CONTAINER_OF(last, struct shell_history_item, dnode);
+		if ((h_item->len == len) &&
+		    (memcmp(h_item->data, line, len) == 0)) {
+			return;
+		}
+	}
+
+	/* Allocate space for a new item. Remove oldest entries until
+	 * allocation succeeds.
+	 */
+	do {
+		h_item = k_heap_alloc(history->heap,
+				sizeof(struct shell_history_item) + len,
+				K_NO_WAIT);
+		if (h_item != NULL) {
+			break;
+		}
+	} while (remove_from_tail(history));
+
+	if (h_item == NULL) {
+		return;
+	}
+
+	h_item->len = (uint16_t)len;
+	memcpy(h_item->data, line, len);
+	sys_dlist_append(&history->list, &h_item->dnode);
+
+	history->current = NULL;
 }

