+
+	/* Negative duration → K_NO_WAIT */
+	if (ts.tv_sec < 0) {
+		timeout = Z_TIMEOUT_TICKS(0);
+		goto done;
+	}
+
+	/* Zero duration → K_NO_WAIT */
+	if ((ts.tv_sec == 0) && (ts.tv_nsec == 0)) {
+		timeout = Z_TIMEOUT_TICKS(0);
+		goto done;
+	}
+
+	/* Maximum representable timespec → K_FOREVER */
+	if ((ts.tv_sec == SYS_TIME_T_MAX) && (ts.tv_nsec == (long)(NSEC_PER_SEC - 1))) {
+		timeout = Z_FOREVER;
+		goto done;
