+	if (u64_mul_overflow((uint64_t)ts.tv_sec, (uint64_t)NSEC_PER_SEC, &total_nsec) ||
+	    u64_add_overflow(total_nsec, (uint64_t)ts.tv_nsec, &total_nsec)) {
+		/* Overflow → cap at K_TICK_MAX */
+		timeout = Z_TIMEOUT_TICKS(K_TICK_MAX);
+	} else {
+		uint64_t ticks = k_ns_to_ticks_ceil64(total_nsec);
+
+		if (ticks > (uint64_t)K_TICK_MAX) {
+			timeout = Z_TIMEOUT_TICKS(K_TICK_MAX);
+		} else {
