+		struct timespec conv_ts;
+
+		timespec_from_timeout(timeout, &conv_ts);
+		rem->tv_sec = ts.tv_sec - conv_ts.tv_sec;
+		rem->tv_nsec = ts.tv_nsec - conv_ts.tv_nsec;
+		(void)timespec_normalize(rem);
