patch:
--- lib/os/cbprintf_packaged.c
+++ lib/os/cbprintf_packaged.c
@@ -223,7 +223,7 @@
 static int append_string(cbprintf_convert_cb cb, void *ctx, const char *str, uint16_t strl)
 {
 	if (cb == NULL) {
-		return 1 + strlen(str);
+		return 1 + strlen(str) + 1;
 	}

 	strl = strl > 0 ? strl : strlen(str) + 1;
@@ -918,5 +918,262 @@
 			     uint16_t *strl,
 			     size_t strl_len)
 {
-    /* MASKED - implement this function */
-}
+#define STR_POS_RO_FLAG BIT(7)
+#define STR_POS_MASK BIT_MASK(7)
+#define MAX_STR 16
+
+	bool do_ro_str = !!(flags & CBPRINTF_PACKAGE_CONVERT_RO_STR);
+	bool do_rw_str = !!(flags & CBPRINTF_PACKAGE_CONVERT_RW_STR);
+	bool keep_ro_str = !!(flags & CBPRINTF_PACKAGE_CONVERT_KEEP_RO_STR);
+
+	if (in_packaged == NULL) {
+		return -EINVAL;
+	}
+
+	struct cbprintf_package_hdr_ext *hdr = in_packaged;
+	uint8_t *buf = in_packaged;
+
+	if (in_len == 0) {
+		in_len = get_package_len(in_packaged);
+	}
+
+	unsigned int args_size = hdr->hdr.desc.len * sizeof(int);
+	unsigned int s_nbr     = hdr->hdr.desc.str_cnt;
+	unsigned int ro_nbr    = hdr->hdr.desc.ro_str_cnt;
+	unsigned int rw_nbr    = hdr->hdr.desc.rw_str_cnt;
+
+	size_t prefix_size = sizeof(*hdr) + args_size;
+
+	uint8_t *ro_start  = buf + prefix_size;
+	uint8_t *rw_start  = ro_start + ro_nbr;
+	uint8_t *str_start = rw_start + 2 * rw_nbr;
+
+	/* Per-RO-entry: keep as-is or convert to appended string. */
+	bool ro_keep[MAX_STR];
+
+	/* Per-RW-entry action. */
+	enum { RW_KEEP, RW_STR, RW_RO, RW_SKIP } rw_act[MAX_STR];
+	uint8_t rw_ro_byte[MAX_STR]; /* position byte for RW_RO */
+
+	/* New appended strings info. */
+	uint8_t  new_str_pos[MAX_STR];
+	uint16_t new_str_slen[MAX_STR];
+	unsigned int new_str_cnt = 0;
+
+	unsigned int new_ro_nbr = 0;
+	unsigned int new_rw_nbr = 0;
+	unsigned int new_s_nbr = s_nbr;
+
+	size_t out_len = prefix_size;
+	unsigned int slen_idx = 0;
+
+	/*
+	 * Phase 1: walk through RO and RW entries, decide what to keep
+	 * or convert, calculate output size, and (when cb == NULL) store
+	 * string lengths into @p strl.
+	 */
+
+	for (unsigned int i = 0; i < ro_nbr; i++) {
+		uint8_t pos = ro_start[i] & STR_POS_MASK;
+		const char *str = *(const char **)(buf + pos * sizeof(int));
+
+		if (do_ro_str) {
+			uint16_t slen;
+
+			if (cb == NULL) {
+				slen = strlen(str) + 1;
+				if (strl != NULL && slen_idx < strl_len) {
+					strl[slen_idx] = slen;
+				}
+			} else {
+				slen = (strl != NULL && slen_idx < strl_len)
+					? strl[slen_idx] : 0;
+			}
+
+			new_str_pos[new_str_cnt] = pos;
+			new_str_slen[new_str_cnt] = slen;
+			new_str_cnt++;
+			new_s_nbr++;
+
+			out_len += append_string(NULL, NULL, str, slen);
+			ro_keep[i] = false;
+			slen_idx++;
+		} else {
+			ro_keep[i] = true;
+			new_ro_nbr++;
+			out_len += 1;
+		}
+	}
+
+	for (unsigned int i = 0; i < rw_nbr; i++) {
+		uint8_t pos = rw_start[2 * i + 1];
+		const char *str = *(const char **)(buf + pos * sizeof(int));
+		bool str_is_ro = ptr_in_rodata(str);
+
+		if (str_is_ro) {
+			if (do_ro_str) {
+				uint16_t slen;
+
+				if (cb == NULL) {
+					slen = strlen(str) + 1;
+					if (strl != NULL && slen_idx < strl_len) {
+						strl[slen_idx] = slen;
+					}
+				} else {
+					slen = (strl != NULL && slen_idx < strl_len)
+						? strl[slen_idx] : 0;
+				}
+
+				new_str_pos[new_str_cnt] = pos;
+				new_str_slen[new_str_cnt] = slen;
+				new_str_cnt++;
+				new_s_nbr++;
+
+				out_len += append_string(NULL, NULL, str, slen);
+				rw_act[i] = RW_STR;
+				slen_idx++;
+			} else if (keep_ro_str) {
+				rw_act[i] = RW_RO;
+				rw_ro_byte[i] = pos | STR_POS_RO_FLAG;
+				new_ro_nbr++;
+				out_len += 1;
+			} else {
+				rw_act[i] = RW_SKIP;
+			}
+		} else {
+			if (do_rw_str) {
+				uint16_t slen;
+
+				if (cb == NULL) {
+					slen = strlen(str) + 1;
+					if (strl != NULL && slen_idx < strl_len) {
+						strl[slen_idx] = slen;
+					}
+				} else {
+					slen = (strl != NULL && slen_idx < strl_len)
+						? strl[slen_idx] : 0;
+				}
+
+				new_str_pos[new_str_cnt] = pos;
+				new_str_slen[new_str_cnt] = slen;
+				new_str_cnt++;
+				new_s_nbr++;
+
+				out_len += append_string(NULL, NULL, str, slen);
+				rw_act[i] = RW_STR;
+				slen_idx++;
+			} else {
+				rw_act[i] = RW_KEEP;
+				new_rw_nbr++;
+				out_len += 2;
+			}
+		}
+	}
+
+	/* Add existing appended strings size. */
+	size_t existing_str_len = 0;
+
+	if (s_nbr > 0) {
+		uint8_t *s = str_start;
+
+		for (unsigned int i = 0; i < s_nbr; i++) {
+			size_t sl = 1 + strlen((const char *)(s + 1)) + 1;
+
+			existing_str_len += sl;
+			s += sl;
+		}
+	}
+	out_len += existing_str_len;
+
+	if (cb == NULL) {
+		return out_len;
+	}
+
+	/*
+	 * Phase 2: stream the output package through the callback.
+	 */
+	int ret;
+
+	/* 1. Updated header. */
+	struct cbprintf_package_hdr_ext new_hdr;
+
+	memcpy(&new_hdr, hdr, sizeof(new_hdr));
+	new_hdr.hdr.desc.str_cnt   = new_s_nbr;
+	new_hdr.hdr.desc.ro_str_cnt = new_ro_nbr;
+	new_hdr.hdr.desc.rw_str_cnt = new_rw_nbr;
+
+	ret = cb(&new_hdr, sizeof(new_hdr), ctx);
+	if (ret < 0) {
+		return ret;
+	}
+
+	/* 2. Arguments (unchanged from input). */
+	ret = cb(buf + sizeof(*hdr), args_size, ctx);
+	if (ret < 0) {
+		return ret;
+	}
+
+	/* 3. Remaining RO positions (kept as-is). */
+	for (unsigned int i = 0; i < ro_nbr; i++) {
+		if (ro_keep[i]) {
+			ret = cb(&ro_start[i], 1, ctx);
+			if (ret < 0) {
+				return ret;
+			}
+		}
+	}
+
+	/* 4. Converted RW→RO positions. */
+	for (unsigned int i = 0; i < rw_nbr; i++) {
+		if (rw_act[i] == RW_RO) {
+			ret = cb(&rw_ro_byte[i], 1, ctx);
+			if (ret < 0) {
+				return ret;
+			}
+		}
+	}
+
+	/* 5. Remaining RW entries (kept as-is). */
+	for (unsigned int i = 0; i < rw_nbr; i++) {
+		if (rw_act[i] == RW_KEEP) {
+			ret = cb(&rw_start[2 * i], 2, ctx);
+			if (ret < 0) {
+				return ret;
+			}
+		}
+	}
+
+	/* 6. Existing appended strings. */
+	if (existing_str_len > 0) {
+		ret = cb(str_start, existing_str_len, ctx);
+		if (ret < 0) {
+			return ret;
+		}
+	}
+
+	/* 7. New appended strings. */
+	for (unsigned int i = 0; i < new_str_cnt; i++) {
+		uint8_t pos = new_str_pos[i];
+
+		ret = cb(&pos, 1, ctx);
+		if (ret < 0) {
+			return ret;
+		}
+
+		const char *str = *(const char **)(buf + pos * sizeof(int));
+
+		ret = append_string(cb, ctx, str, new_str_slen[i]);
+		if (ret < 0) {
+			return ret;
+		}
+	}
+
+	/* Signal end of output. */
+	cb(NULL, 0, ctx);
+
+	return out_len;
+
+#undef STR_POS_RO_FLAG
+#undef STR_POS_MASK
+#undef MAX_STR
+}

